"""
MKT Original — Mark 14
Output: data/commentary/mkt-original/mark.json
Skips already-present: 14:36, 14:62

Key decisions:
- 14:3 pistikēs: rendered "pure/genuine" (not pistachio-nard) as most probable
- 14:24 "new covenant": kainēs omitted from best MSS (NA28); noted as absent
- 14:41 apechei: acknowledged as one of Mark's most disputed words
- 14:51-52 neaniskos: the naked young man treated as deliberately mysterious
- 14:44 kataphilēsen: the intensive compound form noted
- 14:71 anathematizein: the strongest oath form available
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

MARK_14 = {
"14": {
"1": "<p><strong>to pascha kai ta azyma / meta dyo hēmeras</strong> — the Passover and Unleavened Bread / after two days — <em>pascha</em> is the Greek transliteration of Aramaic/Hebrew <em>pesach</em> (Passover), rooted in the verb <em>pasach</em> (to pass over, to spare — Exod 12:13). <em>Azyma</em> (unleavened, without yeast) names the seven-day festival that immediately followed Passover (Lev 23:5–6). Mark's temporal marker <em>meta dyo hēmeras</em> (after two days) places the narrative two days before the Passover meal, creating the Passion Week timeline.</p>",
"2": "<p><strong>mē en tē heortē / thorubos</strong> — not during the festival / riot/uproar — <em>heortē</em> (festival, feast) — the leaders calculate political timing. <em>Thorubos</em> (uproar, riot, tumult) — their concern is crowd management, not justice. Jerusalem's Passover population swelled from ~50,000 to estimates of 100,000–200,000+ pilgrims, making public order genuinely precarious. The leaders intend stealth; instead Judas provides a private opportunity.</p>",
"3": "<p><strong>myrou nardou pistikēs polutelos / kateraxa</strong> — nard ointment/perfume of pure quality, very expensive / having broken — <em>nardos</em> is spikenard, an aromatic plant from the Himalayan foothills, imported at great cost. <em>Pistikēs</em> is disputed: most likely from <em>pistos</em> (faithful, trustworthy → genuine/pure); alternatively a trade term. <em>Polutelos</em> (very costly, extremely expensive — superlative register). <em>Kateraxen</em> (having broken — the whole flask poured, not just a portion). Mark names the home as <em>Simōnos tou leprou</em> (Simon the Leper) — the healed condition still defining the person socially.</p>",
"4": "<p><strong>aganaktountes / eis ti hē apōleia hautē</strong> — being indignant / for what purpose this waste/loss — <em>aganakteō</em> (to be indignant, vexed, offended) — an emotion of moral-social displeasure. <em>Apōleia</em> (waste, destruction, loss) — the same word used for Judas Iscariot (<em>huios tēs apōleias</em>, son of destruction, John 17:12) and for the one who is perishing (2 Thess 2:3). Their economic calculation labels an act of worship as destruction.</p>",
"5": "<p><strong>epano dēnariōn triakosiōn / enebrimōnto autē</strong> — above 300 denarii / they were rebuking/scolding her — 300 denarii = approximately one year's daily wages for a laborer. <em>Enebrimōnto autē</em> (they were scolding, rebuking her) — the verb <em>embrimaomai</em> conveys strong emotional reproach, almost a snorting of indignation. John 12:4–5 attributes the complaint specifically to Judas Iscariot.</p>",
"6": "<p><strong>kalon ergon / egazato eis eme</strong> — beautiful/good work / she has done for me — <em>kalon ergon</em> (beautiful work, excellent deed) — <em>kalos</em> combines the beautiful and the good; this is not merely a morally good act but an aesthetically beautiful one, fitting its object. The phrase appears in Matthew 5:16 (let your light shine so they may see your <em>kala erga</em>). Jesus's defense of the woman is emphatic: <em>aphete autēn</em> (leave her alone).</p>",
"7": "<p><strong>pantote... eme de ou pantote / eupoiēsai</strong> — always... me not always / to do good — the contrast is sharp: the poor (<em>ptōchous</em>) are a permanent fixture of social life and always available for charitable acts (<em>eupoiēsai</em>, to do well/good to). Jesus's physical presence is temporary and unique. The statement is not a dismissal of concern for the poor (Deut 15:11 underlies it) but a corrective about priority and occasion.</p>",
"8": "<p><strong>proelaben myrisai to soma mou eis ton entaphiasmon</strong> — she has anointed my body beforehand for burial — <em>proelaben</em> (she took beforehand, she anticipated) — the woman's act is retroactively interpreted as prophylactic burial preparation. <em>Entaphiasmos</em> (preparation for burial, burial rites) — Jesus names what will shortly happen to his body and claims this act as its preparation. The anointing that should have happened at the tomb (16:1) happens here at the supper.</p>",
"9": "<p><strong>eis to euangelion / eis mnēmosynon autēs</strong> — into/with the gospel / for a memorial of her — <em>euangelion</em> (good news/gospel) — wherever the gospel (<em>euangelion</em>, the same word from Mark's opening, 1:1) is proclaimed throughout the world (<em>eis holon ton kosmon</em>), this woman's act will be told. <em>Mnēmosynon</em> (memorial, remembrance) — only here and in Acts 10:4 in the NT. Jesus guarantees the woman's act a memorial that transcends geography and time.</p>",
"10": "<p><strong>Ioudas Iskariōth / paradoi auton</strong> — Judas Iscariot / to betray him — the juxtaposition of the woman's lavish devotion (vv.3–9) with Judas's defection is stark. <em>Iskariōth</em>: probably from Hebrew <em>ish Qeriyot</em> (man of Kerioth, a Judean town) — making Judas the only non-Galilean of the Twelve. <em>Paradoi</em> (subjunctive of <em>paradidōmi</em> — to hand over, betray) — the verb that has threaded through the passion predictions now moves from announcement to action.</p>",
"11": "<p><strong>echarēsan / argyrion / eukairos</strong> — they rejoiced / silver money / opportunely — <em>echarēsan</em> (they rejoiced, were glad) — the leaders' emotional response to Judas's offer is joy. <em>Argyrion</em> (silver, silver coins) — Mark does not specify the amount; Matthew 26:15 names 30 pieces of silver (Zech 11:12–13). <em>Eukairos</em> (at the right moment, opportunely) — Judas seeks an occasion (<em>pōs... eukairos auton paradoi</em>): the emphasis is on a private opportunity without the crowd.</p>",
"12": "<p><strong>prōtē hēmera tōn azymōn / ethyon to pascha</strong> — the first day of the Unleavened Bread / when they slaughtered the Passover — the first day of Unleavened Bread technically began after Passover (Nisan 14), but Josephus and Second Temple usage treated the Passover sacrifice day as the first of the festival complex. <em>Ethyon to pascha</em> (they were sacrificing the Passover lamb) — the temple sacrifices began on Nisan 14 afternoon. The disciples ask where Jesus will eat the <em>pascha</em> (Passover meal), placing the Last Supper in the Passover context.</p>",
"13": "<p><strong>keramion hydatos bastazōn</strong> — carrying a clay jar of water — water-carrying was typically women's work in first-century Palestine; a man carrying a water jar would be conspicuous. The sign may be a prior arrangement or a supernatural foreknowledge on Jesus's part. Either way, the instruction parallels the triumphal entry preparation (11:2–3) in its confident pre-arrangement.</p>",
"14": "<p><strong>katalyma / pascha / phagō</strong> — guest room/lodging / Passover / I may eat — <em>katalyma</em> (lodging room, guest room) — the same word used for the inn in Luke 2:7. It refers to a room reserved for guests in a private home, not a commercial inn (<em>pandocheion</em>). Jesus's instruction names himself with the honorific <em>ho didaskalos</em> (the Teacher) — the form a disciple would use to identify his rabbi.</p>",
"15": "<p><strong>anagaion mega estrōmenon hetoimon</strong> — a large upper room spread/furnished and ready — <em>anagaion</em> (upper room, second-story room) — a hapax legomenon in Mark (also Luke 22:12), referring to the elevated room of a larger house, typically used for special gatherings. <em>Estrōmenon</em> (furnished, spread out — perfect passive of <em>strōnnymi</em>, to spread, to furnish with couches for reclining). The room is already prepared (<em>hetoimon</em>, ready).</p>",
"16": "<p><strong>hōs eipen autois</strong> — just as he told them — the disciples' discovery that everything was exactly as Jesus predicted (<em>hōs eipen autois</em>) continues Mark's pattern of emphasizing Jesus's authoritative foreknowledge of the Passion events. The precision of fulfilled arrangements is one of the ways Mark underscores divine sovereignty threading through the passion narrative.</p>",
"17": "<p><strong>opsias genomenēs / meta tōn dōdeka</strong> — evening having come / with the Twelve — <em>opsia</em> (evening) — in Jewish reckoning, the new day began at sunset. Passover (Nisan 15) thus began at sunset on Nisan 14 evening. Jesus's arrival with <em>hoi dōdeka</em> (the Twelve) — the formal number — marks this as the formal Passover gathering. The specification of the Twelve is significant given that one of them will betray and one will deny.</p>",
"18": "<p><strong>anakeimenōn / ho esthiōn met' emou</strong> — reclining at table / the one eating with me — <em>anakeimai</em> (to recline, to lie back at table) — the reclining posture at meals was Hellenistic-Roman and was adopted at Passover in Second Temple Judaism as a sign of freedom (slaves stood to eat). <em>Ho esthiōn met' emou</em> (the one eating with me) echoes Psalm 41:9 LXX: <em>ho esthiōn artous mou emegalynen ep' eme pternismon</em> (the one eating my bread has lifted his heel against me).</p>",
"19": "<p><strong>heis kath' heis / mēti egō</strong> — one by one / surely not I — <em>heis kath' heis</em> (one after another, one by one) — a Markan idiom (also 14:35 variant; John 8:9). The pattern of individual self-examination (<em>mēti egō</em>) — the interrogative particle <em>mēti</em> expects a negative answer (literally: am I the one? — expecting the answer no) — reveals the disciples' combination of self-doubt and self-exculpation. Each voices a protestation of innocence that will shortly be tested.</p>",
"20": "<p><strong>heis tōn dōdeka / embaptomenos met' emou eis to tryblion</strong> — one of the Twelve / the one dipping with me into the bowl — <em>heis tōn dōdeka</em> (one of the Twelve) — the repetition of the Twelve as the frame of betrayal is deliberate: the intimacy of shared table intensifies the treachery. <em>Tryblion</em> (common dish, bowl) — shared dipping into a single bowl was a mark of table-fellowship and trust. The betrayal is embedded in the gesture of shared meal.</p>",
"21": "<p><strong>ho huios tou anthrōpou hypagei / kathōs gegraptai / ouai / kalon ēn autō</strong> — the Son of Man goes / as it is written / woe / it was good for him — <em>hypagei</em> (goes away, departs — present tense, immediacy) framed by <em>kathōs gegraptai</em> (as it is written — divine scriptural necessity). The tension between divine necessity and human responsibility is at its sharpest here: the betrayal is both ordained and culpable. <em>Kalon ēn autō ei ouk egennēthē ho anthrōpos ekeinos</em> (it were better for that man if he had not been born) — a stark statement about moral accountability that transcends individual psychology.</p>",
"22": "<p><strong>eulogēsas / eklasen / edōken / labete, touto estin to soma mou</strong> — having blessed/given thanks / broke / gave / take, this is my body — The sequence <em>labon... eulogēsas... eklasen... edōken</em> (having taken... having given thanks/blessed... broke... gave) recurs verbatim in 6:41 (feeding of 5000), establishing a deliberate pattern. <em>Eulogēsas</em> (having blessed) — the <em>berakah</em> (Jewish blessing prayer) over bread. <em>Touto estin to soma mou</em> (this is my body) — the demonstrative pronoun <em>touto</em> (this) without qualification. The Greek <em>estin</em> (is) has generated centuries of debate over what kind of identity-claim is being made.</p>",
"23": "<p><strong>eucharistēsas / epion ex autou pantes</strong> — having given thanks / they all drank from it — <em>eucharistēsas</em> (having given thanks — from <em>eucharistia</em>, thanksgiving, the root of the English Eucharist). Note the shift from <em>eulogēsas</em> (blessed, for the bread) to <em>eucharistēsas</em> (thanked, for the cup) — both are thanksgiving prayers but with slightly different nuance. <em>Epion ex autou pantes</em> (they all drank from it) — Mark notes universal participation; Matthew 26:27 adds Jesus's explicit command to drink.</p>",
"24": "<p><strong>touto estin to haima mou tēs diathēkēs / to ekchhynnomenon hyper pollōn</strong> — this is my blood of the covenant / the one being poured out for many — <em>diathēkē</em> (covenant, will/testament) — in the LXX this translates <em>berith</em> (covenant). Mark's text does not include <em>kainēs</em> (new; present in Luke 22:20, 1 Cor 11:25); the best MSS (Sinaiticus, Vaticanus) simply read <em>tēs diathēkēs</em>. The phrase echoes Exodus 24:8 (<em>idou to haima tēs diathēkēs</em> — the blood of the covenant, Moses's covenant ratification). <em>Ekchhynnomenon</em> (being poured out — present participle, happening in the very breaking of bread) <em>hyper pollōn</em> (for many — Isa 53:12 echo).</p>",
"25": "<p><strong>ouketi ou mē piō / heōs tēs hēmeras ekeinēs / kainon en tē basileia tou theou</strong> — I will certainly no more drink / until that day / new in the kingdom of God — the double negative <em>ouketi ou mē</em> is emphatic absolute negation of future drinking. Jesus takes a vow of abstinence from the fruit of the vine until the kingdom arrives. <em>Kainon</em> (new — qualitatively new, not just subsequent) — the eschatological feast will be categorically new. The vow creates anticipatory tension — when will it be fulfilled? The resurrection meals (Luke 24:30–31; John 21:13) begin the answer.</p>",
"26": "<p><strong>hymnēsantes / eis to Oros tōn Elaiōn</strong> — having sung a hymn / to the Mount of Olives — <em>hymnēsantes</em> (having sung a hymn) — at Passover, the <em>Hallel</em> (Psalms 113–118) was divided: Psalms 113–114 sung before the meal, Psalms 115–118 after. The group's final hymn likely included Psalm 118 — which Jesus had cited twice in the past days (11:9–10; 12:10–11). The Mount of Olives (<em>Oros tōn Elaiōn</em>) was where Zechariah 14:4 expected divine intervention; it is also where David fled weeping from Absalom (2 Sam 15:30).</p>",
"27": "<p><strong>skandalisthēsesthe / pataxō ton poimena / ta probata diaskorpisthēsontai</strong> — you will all be made to stumble / I will strike the shepherd / the sheep will be scattered — <em>skandalisthēsesthe</em> (you will be caused to stumble/fall away) from <em>skandalizomai</em> — to be tripped, to become an occasion of offense or apostasy. Zechariah 13:7 citation: <em>pataxate ton poimena kai diaskorpisthēsontai ta probata</em> (strike the shepherd and the sheep will be scattered). Jesus applies the divine judgment of Zechariah's striking to his own arrest — he is the shepherd being struck.</p>",
"28": "<p><strong>meta to egerthēnai me / proaxō hymas eis tēn Galilaian</strong> — after my being raised / I will go before you to Galilee — the passive <em>egerthēnai</em> (being raised — divine passive) is woven into the announcement of the scattering: resurrection and regathering are already foretold in the prediction of abandonment. <em>Proaxō</em> (I will go before/ahead of you) — the same verb used for the colt untying (11:2 variant) and the disciples going ahead. Galilee, where the disciples were called, will be where they are re-commissioned.</p>",
"29": "<p><strong>ei kai pantes skandalisthēsontai, all' ouk egō</strong> — even if all are caused to stumble, yet not I — Peter's protestation uses the strongest concessive structure available: <em>ei kai</em> (even if) acknowledges the possibility of universal failure while exempting himself. The irony is complete: Peter's self-confidence is the setup for the most detailed denial account in the Gospel. His boast is immediately countered by Jesus's specific prediction.</p>",
"30": "<p><strong>dis alektora phōnēsai / treis aparnēsē me</strong> — before a cock crows twice / you will disown me three times — Mark uniquely specifies <em>dis</em> (twice) — the cock crows twice in Mark's account (v.68, 72). The other Gospels mention only one crow. <em>Aparnēsē</em> (you will deny/disown — future indicative, not subjunctive — certainty, not possibility). <em>Sēmeron</em> (today) and <em>en tē nukti tautē</em> (in this night) — the denial is immediate and specific.</p>",
"31": "<p><strong>ek perissou / syn soi apothanein / ou mē aparnēsomai / pantes de hōsautōs elegon</strong> — vehemently/exceedingly / to die with you / I will absolutely not disown you / and all likewise were saying — <em>ek perissou</em> (out of excess, exceedingly, emphatically) intensifies Peter's vehemence. <em>Ou mē aparnēsomai</em> (I will absolutely not disown) — double negative, the strongest denial of future denial. <em>Pantes de hōsautōs elegon</em> (and all were likewise saying — imperfect, ongoing declarations) — the plural failure is prepared alongside the individual failure.</p>",
"32": "<p><strong>Gethsēmani / kathisate hōde heōs proseuxōmai</strong> — Gethsemane / sit here while I pray — <em>Gethsēmani</em> is Greek transliteration of Aramaic <em>gat shemane</em> (oil press) — an olive grove on the lower slopes of the Mount of Olives where olive oil was extracted. The irony of the name is rich: Jesus will be pressed here as olives are pressed. The instruction to the disciples (<em>kathisate hōde</em>, sit here) separates them from the inner three, then Jesus separates further from the three.</p>",
"33": "<p><strong>ekthambein / adēmonein</strong> — to be greatly alarmed/astonished / to be in great distress/troubled — <em>ekthambein</em> (to be greatly amazed, alarmed — a compound of <em>thambos</em>, astonishment/terror) and <em>adēmonein</em> (to be in anguish, heavily distressed, at a loss — the etymology uncertain; possibly related to being away from home, out of one's element). These are among the strongest Greek terms for emotional-psychological distress available. Mark's account of Gethsemane is more raw than the parallel accounts.</p>",
"34": "<p><strong>perilypos estin hē psychē mou heōs thanatou</strong> — my soul is deeply grieved to death/unto death — <em>perilypos</em> (surrounded by grief, overwhelmed with sorrow — the <em>peri-</em> prefix indicates comprehensive surrounding). Psalm 42:5–6 LXX: <em>hina ti perilypos ei psychē mou</em> (why are you cast down, O my soul) — but Jesus's version is not a rhetorical lament-question but a declaration of actual state. <em>Heōs thanatou</em> (unto death) — grief at the limit of endurable human experience; cf. Jonah 4:9. The command to <em>grēgoreite</em> (keep watch) echoes the Olivet Discourse (13:37).</p>",
"35": "<p><strong>proselthōn mikron / epipten epi tēs gēs / hina... parelthē hē hōra</strong> — going forward a little / fell on the earth / that the hour might pass — <em>epipten epi tēs gēs</em> (fell upon the ground) — the prostration posture of prayer, expressing complete submission. <em>Hōra</em> (hour) — the Passion's appointed time, already marked as coming (2:19–20; 10:38; 13:32; 14:41). The prayer in the imperfect (<em>prosēucheto</em>, he was praying — iterative, ongoing prayer): his request is that if possible the hour might pass.</p>",
"37": "<p><strong>katheudontas / Simōn, katheudeis / ouk ischysas</strong> — sleeping / Simon, are you sleeping? / were you not able — Jesus addresses Peter by his old name <em>Simōn</em>, not Peter — a moment of disappointment that reverts to the pre-calling name. <em>Ouk ischysas mian hōran grēgorēsai</em> (were you not strong enough to watch one hour) — the irony of the one who just swore to die with Jesus unable to remain awake for one hour. <em>Grēgorēsai</em> (to stay awake/watch) — the Gethsemane failure is the Olivet Discourse failure made concrete.</p>",
"38": "<p><strong>grēgoreite kai proseuchesthe / to pneuma prothymon, hē de sarx asthenēs</strong> — watch and pray / the spirit willing, the flesh weak — the pairing of <em>grēgoreite</em> (watch, be awake) and <em>proseuchesthe</em> (pray) — together the disciples' active responsibility for remaining in the posture of readiness. <em>To pneuma prothymon</em> (the spirit is eager/willing, ready) — <em>prothymos</em> (eager, willing, forward-leaning). <em>Hē sarx asthenēs</em> (the flesh is weak) — not a dualistic condemnation of the body but an acknowledgment of creaturely limitation. The saying applies to Jesus himself as he prays against the flesh-limitation.</p>",
"39": "<p><strong>palin apelthōn proseuxato ton auton logon eipōn</strong> — going away again he prayed saying the same word — the repetition of prayer using <em>ton auton logon</em> (the same word/saying) indicates the singular content of Gethsemane's prayer: the cup, the Father's will. Three times Jesus returns to the same petition (vv.35–36, 39, 41). The pattern of threefold repetition mirrors Peter's coming threefold denial — both structures centered on the same night.</p>",
"40": "<p><strong>bebarēmenoi / ouk ēdeisan ti apokrithōsin autō</strong> — weighed down / they did not know what to answer him — <em>bebarēmenoi</em> (weighed down, heavy — perfect passive participle of <em>bareō</em>, to burden, to make heavy; used of sleep-heaviness also in Luke 9:32 at the transfiguration). Their inability to answer (<em>ouk ēdeisan ti apokrithōsin</em>) stands in painful contrast to Peter's earlier verbose confidence. Speechlessness in the face of Jesus's grief.</p>",
"41": "<p><strong>apechei / hē hōra ēlthen / paradidotai ho huios tou anthrōpou</strong> — it is enough / the hour has come / the Son of Man is betrayed — <em>apechei</em> is one of the most debated words in Mark. It can mean: (1) it is enough/sufficient; (2) he/it is far/distant; (3) the debt is paid (a papyrus technical term for receipt of payment). Context and syntax are both ambiguous. Most translations follow option 1. <em>Hē hōra ēlthen</em> (the hour has come — aorist, it arrived) — the appointed time has arrived. <em>Paradidotai</em> (is being betrayed — present passive, ongoing action happening right now).</p>",
"42": "<p><strong>egeiresthe agōmen / idou ho paradidous me</strong> — rise, let us go / look, the one betraying me — <em>egeiresthe</em> (rise! — imperative) echoes the resurrection language that Mark uses for Jesus's own rising (<em>ēgerthē</em>). <em>Agōmen</em> (let us go — hortatory subjunctive) — not flight but advance toward what comes. <em>Engiken</em> (has drawn near) — the betrayer's approach uses the same verb as the kingdom announcement (1:15: <em>ēngiken hē basileia tou theou</em>, the kingdom has drawn near). The hour that has drawn near is the kingdom come in judgment and redemption.</p>",
"43": "<p><strong>heis tōn dōdeka / meta machairōn kai xylōn / para tōn archiereōn</strong> — one of the Twelve / with swords and clubs / from the chief priests — the identification of Judas as <em>heis tōn dōdeka</em> (one of the Twelve) is repeated from v.10 and v.20 — the emphasis on insider betrayal. The crowd's weapons (<em>machairai</em>, swords; <em>xyla</em>, wooden clubs or staves) represent official force from the temple establishment. The night arrest is consistent with the leaders' plan to avoid public confrontation.</p>",
"44": "<p><strong>syssēmon / kataphilēsō / asphalizom kai apagete</strong> — agreed signal / I will kiss — hold him / seize and lead away safely — <em>syssēmon</em> (agreed signal, pre-arranged sign — a hapax legomenon in NT). The kiss (<em>phileō</em>) was a normal greeting between teacher and disciple; using it as a signal of betrayal inverts intimacy into treachery. <em>Kataphilēsō</em> (I will kiss — the compound <em>kata-</em> intensifies: to kiss warmly, affectionately, effusively). The betrayal with an intensified kiss is the ultimate irony of table-fellowship turned to treachery.</p>",
"45": "<p><strong>Rhabbi / katephilēsen auton</strong> — Rabbi / kissed him — Mark uses the Aramaic title <em>Rhabbi</em> (my great one, teacher) — the disciple's form of address for a respected teacher. The verb <em>katephilēsen</em> (aorist of <em>kataphileō</em>) carries out the pre-arranged act. The stark brevity of Mark's account — no extended dialogue as in Matthew — makes the kiss feel more abrupt and cold.</p>",
"46": "<p><strong>epebalan tas cheiras autō kai ekratēsan auton</strong> — they laid their hands on him and seized him — <em>epiballō tas cheiras</em> (to lay hands on, to seize — the standard idiom for arrest by authority). <em>Ekratēsan</em> (they seized/held firmly — from <em>krateō</em>, to be strong, to hold). The same vocabulary was used for the leaders' desire to arrest Jesus (12:12; 14:1) — now their intent is enacted.</p>",
"47": "<p><strong>tis tōn parestēkotōn / apekopsen autou to ōtarion</strong> — one of those standing by / cut off his ear — <em>tis</em> (a certain one, unnamed — Mark leaves the swordsman anonymous; John 18:10 names him as Peter). <em>Ōtarion</em> is a diminutive of <em>ous</em> (ear), meaning &lsquo;little ear&rsquo; — possibly a slice of the outer ear rather than the entire ear. The act is defensive, impulsive, and immediately counterproductive — Jesus will use it as a teaching moment in Luke 22:51 (healing the ear).</p>",
"48": "<p><strong>hōs epi lēstēn / meta machairōn kai xylōn</strong> — as against a bandit/robber / with swords and clubs — <em>lēstēs</em> (robber, bandit, brigand) — also the word used for those crucified alongside Jesus (15:27). Jesus's question exposes the absurdity: armed force against one who taught publicly in the temple daily. The question implicitly asks: if I were dangerous, why not arrest me openly? The answer is the leaders' fear of the crowd (v.2).</p>",
"49": "<p><strong>kath' hēmeran ēmēn pros hymas... hai graphai plērōthōsin</strong> — daily I was with you... the scriptures must be fulfilled — <em>kath' hēmeran</em> (day by day, daily — the public, transparent nature of Jesus's teaching). <em>Plērōthōsin hai graphai</em> (that the scriptures might be fulfilled) — the passive subjunctive expresses divine necessity through scriptural fulfillment. This is the interpretive key Mark places over the entire arrest scene: it is not accident but fulfillment.</p>",
"50": "<p><strong>pantes aphentes auton ephygon</strong> — having left him all fled — five Greek words containing one of the most devastating statements in the Gospels. <em>Pantes</em> (all) — the universality is stark after their universal protestation of loyalty (v.31). <em>Aphentes</em> (having abandoned, left behind — aorist participle of <em>aphiēmi</em>; the same verb for Peter's abandonment of his nets at the call). The fulfillment of Zechariah 13:7 (the scattered sheep, v.27) is immediate and total.</p>",
"51": "<p><strong>neaniskos tis / syndōn / periballomenos epi gymnou</strong> — a certain young man / a linen cloth / having thrown it around his naked body — <em>neaniskos</em> (young man) — Mark's second use; the first is the rich young ruler (10:17 variant); the third will be the angel in the tomb (16:5). <em>Syndōn</em> (linen cloth, fine linen — the same word for Jesus's burial shroud, 15:46) wrapped around a naked (<em>gymnos</em>) body. The identity of this young man has generated sustained scholarly debate: some identify him as Mark himself; others as a baptismal or resurrection-symbolism figure.</p>",
"52": "<p><strong>apheis tēn sindona gymnos ephygen</strong> — leaving behind the linen cloth he fled naked — the young man's flight recapitulates the disciples' flight in miniature — and heightens it: he loses even his covering. <em>Gymnos</em> (naked) — the most shameful state in ancient Mediterranean culture. The episode has no immediate narrative function except to record an embarrassing/curious detail that eyewitness memory would preserve. The linen cloth he leaves behind will appear again as Jesus's burial cloth (15:46).</p>",
"53": "<p><strong>pros ton archierea / synerchontai pantes hoi archiereis</strong> — to the high priest / all the chief priests came together — <em>archiereus</em> (high priest) — Caiaphas, appointed by the Romans and serving ca. 18–36 CE. The assembly of <em>archiereis kai hoi presbyteroi kai hoi grammateis</em> (chief priests and elders and scribes) represents the full Sanhedrin — the seventy-one member Jewish supreme council. Night sessions of the Sanhedrin were technically irregular; the procedural irregularities have been debated extensively.</p>",
"54": "<p><strong>apo makrothen ēkolouthei / sunkatēmenos meta tōn hypēretōn</strong> — at a distance he was following / sitting with the guards — <em>apo makrothen</em> (from far off) — Peter's following is marked by distance; the word creates spatial and moral separation. He gets as far as the courtyard but no further. <em>Sunkatēmenos meta tōn hypēretōn</em> (sitting with the servants/guards) — Peter is physically positioned among Jesus's adversaries while Jesus is being tried. The scene cuts between the two simultaneously, as Mark will do through vv.55–72.</p>",
"55": "<p><strong>to synedrion / martyrian kata tou Iēsou / eis to thanatōsai auton</strong> — the Sanhedrin / testimony against Jesus / to put him to death — <em>synedrion</em> (the sitting-together council — the Sanhedrin). The council is described as <em>ezetoun</em> (imperfect — were seeking, kept seeking) testimony against Jesus; the outcome is already determined, and the process is finding legal cover for a predetermined verdict. <em>Martyrian</em> (testimony, witness) — the legal form is maintained even as the purpose is execution.</p>",
"56": "<p><strong>pseudomarturoun / isai ouk ēsan</strong> — they were testifying falsely / they were not equal/consistent — <em>pseudomarturein</em> (to testify falsely, to give false witness — violates the ninth commandment, Exod 20:16). The legal requirement for capital cases in Jewish law was two or three consistent witnesses (Deut 17:6; 19:15). <em>Isai ouk ēsan</em> (they were not equal/consistent) — the testimonies did not agree with each other, making them inadmissible.</p>",
"57": "<p><strong>anastantes tines</strong> — certain ones standing up — the specific phrase <em>anastantes tines</em> (certain ones standing up) introduces the witness-group that will provide the one charge that requires a direct response from Jesus. Their testimony concerns the temple, the central institution of Jewish identity.</p>",
"58": "<p><strong>ton naon touton ton cheiropoiēton / acheiropoiēton</strong> — this temple made with hands / not made with hands — <em>cheiropoiētos</em> (made-with-hands — a compound adjective) and <em>acheiropoiētos</em> (not-made-with-hands) are theologically loaded terms in the LXX (Isa 2:18; 10:11; 16:12; 19:1) where hand-made gods are idols. A <em>naon acheiropoiēton</em> (sanctuary not-made-with-hands) implies a transcendent, heavenly temple. The witnesses distort Jesus's saying (cf. John 2:19), but the underlying concept — that Jesus would replace the temple with a community or body — is not entirely unfounded.</p>",
"59": "<p><strong>oude houtōs isē ēn hē martyria autōn</strong> — not even so was their testimony equal/consistent — the double failure of the witnesses (v.56 general inconsistency; v.59 the specific temple charge also inconsistent) creates a legal impasse. The Sanhedrin's case cannot proceed to execution on available testimony. The high priest therefore takes the unprecedented step of placing Jesus under direct oath.</p>",
"60": "<p><strong>anastas ho archiereus / oud' apokriē ouden</strong> — the high priest standing up / you answer nothing? — the high priest's rising from his seat is a formal escalation — he takes personal charge of the interrogation. His double question (<em>ti houtoi sou katamarturousin</em>, what do these testify against you?) invites self-incrimination. Jesus's continued silence (<em>esigōpan</em>, v.61) fulfills the servant of Isaiah 53:7 who was silent before his shearers.</p>",
"61": "<p><strong>esigōpan kai ouden apekrinatō / ho christos ho huios tou eulogētou</strong> — was silent and answered nothing / the Christ, the Son of the Blessed One — <em>esigōpan</em> (was silent — imperfect, maintained silence throughout). Isaiah 53:7 LXX: <em>ouk anoigei to stoma autou</em> (he does not open his mouth). <em>Eulogētos</em> (Blessed One) — a circumlocution for God, common in rabbinic usage to avoid the divine name. The high priest's question directly invokes the Messianic title: <em>ho Christos</em> (the Anointed One) and <em>ho huios tou eulogētou</em> (the Son of the Blessed One) — both drawn from the highest claims Jesus's followers made about him.</p>",
"63": "<p><strong>diarrēxas tous chitōnas autou</strong> — tearing his tunics — the high priest's tearing of his garments was a prescribed response to blasphemy in Jewish law (m. Sanh. 7:5): hearing a capital blasphemy, the judge tears his garments and cannot re-stitch them. The plural <em>chitōnas</em> (inner garments, tunics) indicates the formal gesture. The question that follows (<em>ti eti chreian echomen martyrōn</em>, why do we still have need of witnesses?) signals that Jesus's own words have provided the charge.</p>",
"64": "<p><strong>blasphēmias / pantes katekrinan auton enochos thanatou einai</strong> — blasphemy / they all condemned him as liable to death — <em>blasphēmia</em> (blasphemy — speaking words that dishonor or usurp the divine) — in Jewish law, capital blasphemy involved pronouncing the divine Name (m. Sanh. 7:5). Jesus's <em>egō eimi</em> combined with the Psalm 110 and Daniel 7 imagery was heard as a divine claim. <em>Pantes katekrinan</em> (they all condemned) — the universal condemnation by the council.</p>",
"65": "<p><strong>emptein autō / perikalyptein to prosōpon autou / kolaphizein auton / prophēteuson</strong> — to spit on him / to blindfold his face / to strike him with the fist / Prophesy! — <em>emptuō</em> (to spit on — the supreme gesture of contempt in Mediterranean culture; Num 12:14; Isa 50:6 LXX: <em>to de prosōpon mou ouk apestrepsamen apo aischynēs emptysmatōn</em>). <em>Kolaphizein</em> (to strike with the fist, to box). The <em>prophēteuson</em> (Prophesy! — command) is ironic: as they mock the prophet with blindfolded blows, asking who struck him, he is simultaneously on trial for truthful prophecy about his death and resurrection.</p>",
"66": "<p><strong>katō en tē aulē / paidiskōn tou archiereōs</strong> — below in the courtyard / of the servant girls of the high priest — the spatial marker <em>katō</em> (below, in the courtyard) contrasts with Jesus's position above in the inner chamber. <em>Paidiskē</em> (servant girl, female slave) — one of the lowest-status people in the household. Peter's faith is exposed by the lowest-ranking member of the high priest's household, not by a person of authority.</p>",
"67": "<p><strong>idousa ton Petron / kai embleplousa autō</strong> — seeing Peter / and looking closely at him — <em>emblepsasa</em> (looking closely, peering intently — <em>em-</em> prefix intensifies the gaze). The servant girl's scrutiny is deliberate: she recognizes him. <em>Kai su meta tou Nazarēnou Iēsou ēstha</em> (you also were with the Nazarene, Jesus) — identifying Jesus by his Galilean town of origin (<em>Nazarēnos</em>).</p>",
"68": "<p><strong>ērnēsato / oute oida oute epistamai ti sy legeis / proaulion</strong> — he denied / I neither know nor understand what you are saying / the forecourt — <em>ērnēsato</em> (he denied — aorist of <em>arneomai</em>, to deny, disown) — the first denial. The form of denial (<em>oute oida oute epistamai</em>, I neither know nor understand) uses two different Greek verbs for knowing, emphasizing the completeness of professed ignorance. <em>Proaulion</em> (the forecourt, gateway vestibule — a hapax in the NT), the threshold of the outer court, signals Peter's physical retreat even as he lingers.</p>",
"69": "<p><strong>hē paidiskē idousa auton ērxato palin legein</strong> — the servant girl seeing him began again to say — the same servant girl (or possibly another, but Mark's <em>hē paidiskē</em> suggests the same) resumes the identification. The <em>palin</em> (again) marks the second encounter. Peter's presence in the forecourt has only delayed, not ended, his exposure.</p>",
"70": "<p><strong>Galilaios ei / hē lalia sou homoiazei</strong> — you are a Galilean / your speech is like them — those standing near identify Peter by his accent: <em>hē lalia sou homoiazei</em> (your manner of speech resembles them) — Galilean Aramaic had a distinctive pronunciation, particularly collapsing of guttural distinctions (Matthew 26:73 adds <em>dēlos gar ei</em>, for you are obvious). Regional dialect functions as unintended identity marker.</p>",
"71": "<p><strong>anathematizein / omnynai / ouk oida ton anthrōpon touton</strong> — to curse / to swear / I do not know this man — <em>anathematizein</em> (to put under a curse, to invoke a curse upon oneself) — the strongest available oath form; to call a curse upon yourself if what you say is false. Combined with <em>omnynai</em> (to swear an oath), this is the most emphatic denial possible. The phrase <em>ton anthrōpon touton</em> (this man) — the impersonal, distancing reference stands in stark contrast to Peter's earlier declarations of willingness to die with him.</p>",
"72": "<p><strong>ek deuterou / anemnēsthē / epibas eklaien</strong> — for the second time / he remembered / going out he wept — <em>ek deuterou</em> (for the second time — Mark's unique detail of the second crow). <em>Anemnēsthē</em> (he remembered — aorist of <em>anamimnēskomai</em>, to remember, to call to mind). The remembering is triggered by the second crow — memory and physical cue aligned. <em>Epibas eklaien</em> — <em>epibas</em> is one of the most difficult words in Mark: possibly &lsquo;throwing himself down&rsquo; (from <em>epiballō</em>), or &lsquo;beginning&rsquo; (from <em>epiballō</em> in the sense of setting to), or &lsquo;going outside&rsquo; (from <em>epibainō</em>). Whatever the precise rendering, the result is: <em>eklaien</em> (he wept — imperfect, was weeping, kept weeping). The chapter ends with the sound of Peter's tears.</p>"
}
}

def main():
    existing = load_comm('mkt-original', 'mark')
    before = sum(len(v) for v in existing.values())
    merge_comm(existing, MARK_14)
    after = sum(len(v) for v in existing.values())
    save_comm('mkt-original', 'mark', existing)
    print(f'  added {after - before} entries (total: {after})')

    import json as _json
    inter = _json.loads((ROOT / 'data' / 'interlinear' / 'mark.json').read_text())
    out = existing
    for ch in ['14']:
        total = len(inter.get(ch, {}))
        present = len(out.get(ch, {}))
        status = 'complete' if present == total else f'MISSING {total - present}'
        print(f'  ch {ch}: {present}/{total} ({status})')

if __name__ == '__main__':
    main()
